import{_ as e,o as d,c as r,ag as a}from"./chunks/framework.BuUvxvtQ.js";const o="/assets/logo.CugPAfXc.png",h="/assets/%E4%BB%BB%E5%8A%A1%E7%8A%B6%E6%80%81.JTe7daIe.png",s=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"OS/FreeRTOS/FreeRTOS.md","filePath":"OS/FreeRTOS/FreeRTOS.md","lastUpdated":1775898880000}'),i={name:"OS/FreeRTOS/FreeRTOS.md"};function l(n,t,p,S,c,u){return d(),r("div",null,[...t[0]||(t[0]=[a('<h3 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h3><p>FreeRTOS是一款开源的实时操作系统，小巧，稳定，移植性强可运行在资源有限的嵌入式设备上，因此成为单片机系统的选择。</p><p><img src="'+o+'" alt="logo"></p><p>官方文档：<a href="https://www.freertos.org/Documentation/00-Overview" target="_blank" rel="noreferrer">FreeRTOS documentation - FreeRTOS™</a></p><p>实时性：Unix 操作系统给每个任务分配同样的运行时间，时间到了就切换到下一个任务。 RTOS 的任务调度器被设计为可预测的，优先级高的任务可以打断优先级低的任务得到及时执行。</p><h3 id="系统文件" tabindex="-1">系统文件 <a class="header-anchor" href="#系统文件" aria-label="Permalink to &quot;系统文件&quot;">​</a></h3><p>系统主要由内核和组件组成，而内核的源文件主要内容如下，<code>portable</code>文件夹下存放的是针对不同平台的移植文件和动态内存分配文件。</p><table tabindex="0"><thead><tr><th>名称</th><th>描述</th></tr></thead><tbody><tr><td>include （文件夹）</td><td>内包含了 FreeRTOS 的头文件</td></tr><tr><td>portable （文件夹）</td><td>内包含了 FreeRTOS 的移植文件</td></tr><tr><td>croutine.c</td><td>协程相关文件</td></tr><tr><td>event_groups.c</td><td>事件相关文件</td></tr><tr><td>list.c</td><td>列表相关文件</td></tr><tr><td>queue.c</td><td>队列相关文件</td></tr><tr><td>stream_buffer.c</td><td>流式缓冲区相关文件</td></tr><tr><td>tasks.c</td><td>任务相关文件</td></tr><tr><td>timers.c</td><td>软件定时器相关文件</td></tr></tbody></table><h3 id="系统移植" tabindex="-1">系统移植 <a class="header-anchor" href="#系统移植" aria-label="Permalink to &quot;系统移植&quot;">​</a></h3><p>系统移植需要将上述文件添到工程目录，需要注意的是<code>portable</code>文件夹中移植文件的选择，针对不同的硬件平台需要选用不同的移植文件。</p><table tabindex="0"><thead><tr><th>硬件平台</th><th>移植文件</th></tr></thead><tbody><tr><td>STM32F1（ARMCC）</td><td>RVDS/ARM_CM3</td></tr><tr><td>STM32F4/ STM32G4（ARMCC）</td><td>RVDS/ARM_CM4F</td></tr><tr><td>STM32F7（ARMCC）</td><td>RVDS/ARM_CM7/r0p1</td></tr><tr><td>STM32H7（ARMCC）</td><td>RVDS/ARM_CM7/r0p1</td></tr><tr><td>STM32H5（ARMClang）</td><td>GCC/ ARM_CM33_NTZ</td></tr></tbody></table><p>同时在<code>MemMang</code>文件夹下还存放着五个动态内存管理的文件，只需要选择一个使用即可。</p><table tabindex="0"><thead><tr><th>文件</th><th>功能</th></tr></thead><tbody><tr><td>heap1.c</td><td>最简单的方法，不允许释放内存。</td></tr><tr><td>heap2.c</td><td>允许释放内存，但不合并相邻的空闲块。</td></tr><tr><td>heap3.c</td><td>简单包装标准 malloc（） 和 free（） 以确保线程安全。</td></tr><tr><td>heap4.c</td><td>合并相邻的空闲块以避免碎片化。包括绝对地址放置选项。</td></tr><tr><td>heap5.c</td><td>在heap4.c的基础上，能够将堆跨越多个不相邻的内存区域。</td></tr></tbody></table><h3 id="系统配置" tabindex="-1">系统配置 <a class="header-anchor" href="#系统配置" aria-label="Permalink to &quot;系统配置&quot;">​</a></h3><p>FreeRTOS支持通过宏定义设置通过预处理来“裁剪”系统，进而满足不同项目对系统的不同需求，这些宏的定义位置在<code>FreeRTOSConfig.h</code>文件内。<code>FreeRTOSConfig.h</code>这个文件需要自行配置，可以参照官方demo中的配置文件和官方文档中宏的作用自行修改。</p><p>配置文件：<a href="https://www.freertos.org/Documentation/02-Kernel/03-Supported-devices/02-Customization" target="_blank" rel="noreferrer">Customization - FreeRTOS™</a></p><h3 id="中断管理" tabindex="-1">中断管理 <a class="header-anchor" href="#中断管理" aria-label="Permalink to &quot;中断管理&quot;">​</a></h3><p>ARM Cortex-M系列的MPU都有如下三个用于屏蔽中断的寄存器：</p><table tabindex="0"><thead><tr><th>寄存器名称</th><th>作用</th></tr></thead><tbody><tr><td>PRIMASK</td><td>只有0位可读可写，设置为1能够屏蔽除 NMI 和 HardFault 外的所有异常和中断。</td></tr><tr><td>FAULTMASK</td><td>只有0位可读可写，设置为 1 用于屏蔽除 NMI 外的所有异常和中断。</td></tr><tr><td>BASEPRI</td><td>只有低 8 位[7:0]可读可写，屏蔽优先级低于其设置的值的中断。</td></tr></tbody></table><p>FreeRTOS就是通过<code>BASEPRI</code>寄存器来管理受其管理的中断的（优先级高于<code>BASEPRI</code>寄存器设置的值的中断不受管理）</p><p>我们知道ARM Cortex-M系列有256个中断，其中16个为系统中断，240个为外部中断，有两个重要的系统中断<code>PendSV</code>和 <code>SysTick</code>，需要设置为最低优先级。</p><ul><li>SysTick： 系统滴答定时器中断，这个中断每隔1ms就触发一次用于判断当前所执行的任务是否为最高优先级是否需要进行任务切换，调用PenSV进行上下问切换。</li><li>PendSV： 可挂起的系统调用中断，这个中断的服务函数主要进行执行任务的切换。</li></ul><p><a href="https://zhuanlan.zhihu.com/p/513133828" target="_blank" rel="noreferrer">SVC和PendSV异常有什么用途？</a></p><p>临界区：</p><p>临界区是指那些必须完整运行的区域，在临界区中的代码必须完整运行不能被打断。在运行临界区的代码的时候就需要将Free RTOS管理的中断关闭，也就是向<code>BASEPRI</code>寄存器写入受FreeRTOS管理的最高优先级的值，进而将受管理的中断屏蔽。</p><p>上述操作通过下列四个宏定义进行：</p><table tabindex="0"><thead><tr><th>宏</th><th>作用</th></tr></thead><tbody><tr><td>taskENTER_CRITICAL()</td><td>用于在非中断中进入临界区</td></tr><tr><td>taskENTER_CRITICAL_FROM_ISR()</td><td>用于从中断中进入临界区</td></tr><tr><td>taskEXIT_CRITICAL()</td><td>用于从非中断中退出临界区</td></tr><tr><td>taskEXIT_CRITICAL_FROM_ISR(x)</td><td>用于从中断中退出临界区</td></tr></tbody></table><p>PS.从中断中进入临界区的区别在于相关函数会先读取<code>BASEPRI</code>的值，并在函数的最后返回这个值，这是为了在后续从中断中退出临界区时恢复<code>BASEPRI</code>寄存器的值。</p><h3 id="列表与列表项" tabindex="-1">列表与列表项 <a class="header-anchor" href="#列表与列表项" aria-label="Permalink to &quot;列表与列表项&quot;">​</a></h3><p>就是链表的应用</p><h3 id="任务管理" tabindex="-1">任务管理 <a class="header-anchor" href="#任务管理" aria-label="Permalink to &quot;任务管理&quot;">​</a></h3><p><img src="'+h+'" alt="任务状态"></p><p>创建任务分为静态创建和动态创建，静态创建堆栈大小固定编译前就已经确定，动态通过malloc函数创建任务堆栈。</p><p>动态创建任务的函数定义堆栈大小的参数单位为字</p><p>任务挂起函数并不支持嵌套，不论使用此函数重复挂起任务多少次，只需调用一次恢复任务的函数，那么任务就不再被挂起。</p><h3 id="启动流程" tabindex="-1">启动流程 <a class="header-anchor" href="#启动流程" aria-label="Permalink to &quot;启动流程&quot;">​</a></h3><h3 id="消息队列" tabindex="-1">消息队列 <a class="header-anchor" href="#消息队列" aria-label="Permalink to &quot;消息队列&quot;">​</a></h3><h4 id="队列" tabindex="-1">队列 <a class="header-anchor" href="#队列" aria-label="Permalink to &quot;队列&quot;">​</a></h4><p>队列用于消息在任务与任务，任务与中断之间的传递。队列中消息以环形缓冲区的形式存储，缓存区的大小在队列创建时确定，每种队列只能存储一种类型的消息。</p><table tabindex="0"><thead><tr><th>函数</th><th>描述</th></tr></thead><tbody><tr><td>xQueueCreate()</td><td>动态方式创建队列</td></tr><tr><td>xQueueCreateStatic()</td><td>静态方式创建队列</td></tr><tr><td>xQueueSend()</td><td>往队列的尾部写入消息</td></tr><tr><td>xQueueSendToBack()</td><td>同 xQueueSend()</td></tr><tr><td>xQueueSendToFront()</td><td>往队列的头部写入消息</td></tr><tr><td>xQueueOverwrite()</td><td>覆写队列消息（只用于队列长度为 1 的情况）</td></tr><tr><td>xQueueSendFromISR()</td><td>在中断中往队列的尾部写入消息</td></tr><tr><td>xQueueSendToBackFromISR()</td><td>同 xQueueSendFromISR()</td></tr><tr><td>xQueueSendToFrontFromISR()</td><td>在中断中往队列的头部写入消息</td></tr><tr><td>xQueueOverwriteFromISR()</td><td>在中断中覆写队列消息（只用于队列长度为 1 的情况）</td></tr><tr><td>xQueueReceive()</td><td>从队列头部读取消息，并删除消息</td></tr><tr><td>xQueuePeek()</td><td>从队列头部读取消息</td></tr><tr><td>xQueueReceiveFromISR()</td><td>在中断中从队列头部读取消息，并删除消息</td></tr><tr><td>xQueuePeekFromISR()</td><td>在中断中从队列头部读取消息</td></tr><tr><td>prvLockQueue()</td><td>队列上锁的函数</td></tr><tr><td>prvUnlockQueue()</td><td>队列解锁的函数</td></tr></tbody></table><h4 id="队列集" tabindex="-1">队列集 <a class="header-anchor" href="#队列集" aria-label="Permalink to &quot;队列集&quot;">​</a></h4><p>一个队列只允许传递同一种数据类型，如果需要传递不同类型的数据就需要设置多个队列，然而对每一个队列都进行轮询效率低下，因此可以通过监听队列集的方式来监视所有被添加到队列集中的队列。任务在监听队列集时，一旦队列集中有任何队列中存在可读消息<code>xQueueSelectFromSet()</code>函数都会返回这个可读队列，进而决定是否要读取这个队列。注意使用队列集功能，需要在 FreeRTOSConfig.h 文件中将配置项 configUSE_QUEUE_SETS 配置为 1。</p><table tabindex="0"><thead><tr><th>函数</th><th>描述</th></tr></thead><tbody><tr><td>xQueueCreateSet()</td><td>创建队列集</td></tr><tr><td>xQueueAddToSet()</td><td>将队列添加到队列集中，被添加队列必须为空</td></tr><tr><td>xQueueRemoveFromSet()</td><td>从队列集中移除队列，被移除队列必须为空</td></tr><tr><td>xQueueSelectFromSet()</td><td>获取队列集中有有效消息的队列</td></tr><tr><td>xQueueSelectFromSetFromISR()</td><td>在中断中获取队列集中有有效消息的队列</td></tr></tbody></table><h3 id="信号量" tabindex="-1">信号量 <a class="header-anchor" href="#信号量" aria-label="Permalink to &quot;信号量&quot;">​</a></h3><p>信号量用于保证任务之间的同步，以及公共资源的有序访问。</p><p>为了避免多个任务通过全局变量传递消息而造成公共资源的访问冲突，使用信号量来保证公共资源的有序访问，只有获得空闲信号量的任务才能访问公共资源，申请获取信号量而未获取到的任务将处于<strong>阻塞状态</strong>直至获取到信号量或者阻塞超时。通过给共享资源建立标志位的方法来实现上述效果，该标志表示该共享资源被占用情况。当一个任务在访问共享资源之前，就可以先对这个标志进行查询，从而在了解资源被占用的情况之后，再来决定自己的行为，这个标志位就是信号量。信号量是通过队列实现有许多种类：</p><ul><li>二值信号量</li><li>计数型信号量</li><li>互斥信号量</li><li>递归互斥信号量</li></ul><h4 id="二值信号量" tabindex="-1">二值信号量 <a class="header-anchor" href="#二值信号量" aria-label="Permalink to &quot;二值信号量&quot;">​</a></h4><p>二值信号量是长度为1的队列，队列只有为空和满两种情况，对应信号量空闲和占有两种状态，也就对应标志位真假两种状态。</p><table tabindex="0"><thead><tr><th>函数</th><th>描述</th></tr></thead><tbody><tr><td>xSemaphoreCreateBinary()</td><td>使用动态方式创建二值信号量</td></tr><tr><td>xSemaphoreCreateBinaryStatic()</td><td>使用静态方式创建二值信号量</td></tr><tr><td>xSemaphoreTake()</td><td>获取信号量</td></tr><tr><td>xSemaphoreTakeFromISR().</td><td>在中断中获取信号量</td></tr><tr><td>xSemaphoreGive()</td><td>释放信号量</td></tr><tr><td>xSemaphoreGiveFromISR()</td><td>在中断中释放信号量</td></tr><tr><td>vSemaphoreDelete()</td><td>删除信号量</td></tr></tbody></table><h4 id="计数信号量" tabindex="-1">计数信号量 <a class="header-anchor" href="#计数信号量" aria-label="Permalink to &quot;计数信号量&quot;">​</a></h4><p>计数信号量是长度大于1的队列，用于做多个资源的标志位或者事件计数。</p><table tabindex="0"><thead><tr><th>函数</th><th>描述</th></tr></thead><tbody><tr><td>xSemaphoreCreateCounting()</td><td>使用动态方式创建计数型信号量</td></tr><tr><td>xSemaphoreCreateCountingStatic()</td><td>使用静态方式创建计数型信号量</td></tr><tr><td>xSemaphoreTake()</td><td>获取信号量</td></tr><tr><td>xSemaphoreTakeFromISR()</td><td>在中断中获取信号量</td></tr><tr><td>xSemaphoreGive()</td><td>释放信号量</td></tr><tr><td>xSemaphoreGiveFromISR()</td><td>在中断中释放信号量</td></tr><tr><td>vSemaphoreDelete()</td><td>删除信号量</td></tr><tr><td>uxSemaphoreGetCount()</td><td>获取计数型信号量资源数</td></tr></tbody></table><h4 id="互斥信号量" tabindex="-1">互斥信号量 <a class="header-anchor" href="#互斥信号量" aria-label="Permalink to &quot;互斥信号量&quot;">​</a></h4><p>互斥信号量和二值信号量一样都是长度为一的队列，不同的是互斥信号量拥有<strong>优先级继承</strong>的机制，当底优先级的任务获取到信号量之后，高优先级任务再去获取信号量会被阻塞，同时低优先级的任务的优先级会被提升到和高优先级任务一样的程度，这样的操作叫做优先级的继承。这样做的目的是为了最大程度上避免优先级反转，即低优先级任务在获取信号量之后被中等优先级的任务抢占执行，导致高优先级的任务一直无法获取到信号量而被一直阻塞。</p><p><strong>需要注意的是中断中不能申请互斥信号量，因为中断的优先级不受操作系统的管制</strong>。</p><table tabindex="0"><thead><tr><th>函数</th><th>描述</th></tr></thead><tbody><tr><td>xSemaphoreCreateMutex()</td><td>使用动态方式创建互斥信号量</td></tr><tr><td>xSemaphoreCreateMutexStatic()</td><td>使用静态方式创建互斥信号量</td></tr><tr><td>xSemaphoreTake()</td><td>获取信号量</td></tr><tr><td>xSemaphoreGive()</td><td>释放信号量</td></tr><tr><td>vSemaphoreDelete()</td><td>删除信号量</td></tr></tbody></table><p>请牢记优先级继承机制的这些特定行为：</p><ul><li>如果一个任务在占用一个互斥锁时没有先释放它已占用的互斥锁， 则可以进一步提升其继承优先级。</li><li>任务在释放其占有的所有互斥锁之前，一直保持最高继承优先级。 这与释放互斥锁的顺序无关。</li><li>如果多个互斥锁被占用，无论在任何一个被占用的互斥锁上等待的任务是否完成等待（超时）， 则任务将保持最高继承优先级 。</li></ul><h4 id="递归互斥信号量" tabindex="-1">递归互斥信号量 <a class="header-anchor" href="#递归互斥信号量" aria-label="Permalink to &quot;递归互斥信号量&quot;">​</a></h4><p>递归互斥信号量是特殊的互斥信号量，在具备互斥信号量的优先级继承特性的同时它允许信号的持有任务多次申请获取信号量，在释放信号量的时候也需要释放相同次数才能真正释放信号量。</p><table tabindex="0"><thead><tr><th>函数</th><th>描述</th></tr></thead><tbody><tr><td>xSemaphoreCreateRecursiveMutex()</td><td>使用动态方式创建递归互斥信号量</td></tr><tr><td>xSemaphoreCreateRecursiveMutexStatic()</td><td>使用静态方式创建递归互斥信号量</td></tr><tr><td>xSemaphoreTakeRecursive()</td><td>获取递归互斥信号量</td></tr><tr><td>xSemaphoreGiveRecursive()</td><td>释放递归互斥信号量</td></tr><tr><td>vSemaphoreDelete()</td><td>删除信号量</td></tr></tbody></table>',62)])])}const m=e(i,[["render",l]]);export{s as __pageData,m as default};
